import { z } from 'zod';
import { CallTemplate, Auth, Serializer, CommunicationProtocol, IUtcpClient, RegisterManualResult } from '@utcp/sdk';

/**
 * Text call template for UTCP client.
 *
 * This template allows passing UTCP manuals or tool definitions directly as text content.
 * It supports both JSON and YAML formats and can convert OpenAPI specifications to UTCP manuals.
 *
 * Attributes:
 *     call_template_type: Always "text" for text call templates.
 *     content: Direct text content of the UTCP manual or tool definitions (required).
 *     base_url: Optional base URL for API endpoints when converting OpenAPI specs. Overrides spec's server configuration.
 *     auth: Always undefined - text call templates don't support authentication.
 *     auth_tools: Optional authentication to apply to generated tools from OpenAPI specs.
 */
interface TextCallTemplate extends CallTemplate {
    call_template_type: 'text';
    content: string;
    base_url?: string;
    auth?: undefined;
    auth_tools?: Auth | null;
    allowed_communication_protocols?: string[];
}
/**
 * Zod schema for TextCallTemplate.
 */
declare const TextCallTemplateSchema: z.ZodType<TextCallTemplate>;
/**
 * Serializer for TextCallTemplate objects.
 */
declare class TextCallTemplateSerializer extends Serializer<TextCallTemplate> {
    toDict(obj: TextCallTemplate): Record<string, unknown>;
    validateDict(obj: Record<string, unknown>): TextCallTemplate;
}

/**
 * REQUIRED
 * Communication protocol for text-based UTCP manuals and tools.
 */
declare class TextCommunicationProtocol implements CommunicationProtocol {
    private _log_info;
    private _log_error;
    /**
     * REQUIRED
     * Register a text manual and return its tools as a UtcpManual.
     */
    registerManual(caller: IUtcpClient, manualCallTemplate: CallTemplate): Promise<RegisterManualResult>;
    /**
     * REQUIRED
     * Deregister a text manual (no-op).
     */
    deregisterManual(caller: IUtcpClient, manualCallTemplate: CallTemplate): Promise<void>;
    /**
     * REQUIRED
     * Execute a tool call. Text protocol returns the content directly.
     */
    callTool(caller: IUtcpClient, toolName: string, toolArgs: Record<string, any>, toolCallTemplate: CallTemplate): Promise<any>;
    /**
     * REQUIRED
     * Streaming variant: yields the full content as a single chunk.
     */
    callToolStreaming(caller: IUtcpClient, toolName: string, toolArgs: Record<string, any>, toolCallTemplate: CallTemplate): AsyncGenerator<any, void, unknown>;
    /**
     * REQUIRED
     * Close the protocol connection (no-op for text protocol).
     */
    close(): Promise<void>;
}

/**
 * Registers the Text protocol's CallTemplate serializer
 * and its CommunicationProtocol implementation.
 * This function is called automatically when the package is imported.
 */
declare function register(override?: boolean): void;

export { type TextCallTemplate, TextCallTemplateSchema, TextCallTemplateSerializer, TextCommunicationProtocol, register };
